const Footer = () => {
  return (
    <footer className="border-t border-slate-200 bg-slate-50 py-8 text-slate-700 dark:border-slate-800 dark:bg-slate-950 dark:text-slate-300">
      <div className="mx-auto flex max-w-7xl flex-col gap-4 px-4 text-center sm:px-6 lg:px-8 lg:flex-row lg:items-center lg:justify-between">
        <p>Built with React, Tailwind CSS, and Framer Motion.</p>
        <p className="text-sm text-slate-500 dark:text-slate-400">© 2026 My React Projects Collection.</p>
      </div>
    </footer>
  );
};

export default Footer;
